import { NavLink, useNavigate } from "react-router-dom";
import { useCart } from "../context/CartContext";
import { useState } from "react";

const categories = [
  { key: "ngu-coc", label: "Ngũ Cốc", icon: "🌾" },
  { key: "banh-mi", label: "Bánh Mì", icon: "🍞" },
  { key: "sua-trung", label: "Sữa & Trứng", icon: "🥛" },
  { key: "thit", label: "Thịt", icon: "🥩" },
  { key: "hai-san", label: "Hải Sản", icon: "🦐" },
  { key: "rau-cu", label: "Rau Củ", icon: "🥦" },
  { key: "trai-cay", label: "Trái Cây", icon: "🍎" },
];

function Menu() {
  const { cartCount } = useCart();
  const navigate = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);

  return (
    <header style={styles.header}>
      {/* Top bar */}
      <div style={styles.topBar}>
        <div style={styles.logo} onClick={() => navigate("/")}>
          <span style={styles.logoIcon}>🛒</span>
          <span style={styles.logoText}>FoodMart</span>
          <span style={styles.logoSub}>Siêu Thị Online</span>
        </div>

        <div style={styles.searchBar}>
          <input
            type="text"
            placeholder="Tìm kiếm thực phẩm..."
            style={styles.searchInput}
            onKeyDown={(e) => {
              if (e.key === "Enter") navigate("/products");
            }}
          />
          <button style={styles.searchBtn}>🔍</button>
        </div>

        <div style={styles.topRight}>
          <div style={styles.cartBtn} onClick={() => navigate("/cart")}>
            <span style={styles.cartIcon}>🛒</span>
            <div style={styles.cartInfo}>
              <span style={styles.cartLabel}>Giỏ hàng</span>
              <span style={styles.cartCount}>{cartCount} sản phẩm</span>
            </div>
            {cartCount > 0 && (
              <span style={styles.cartBadge}>{cartCount}</span>
            )}
          </div>
        </div>
      </div>

      {/* Nav bar */}
      <nav style={styles.navBar}>
        <NavLink
          to="/"
          style={({ isActive }) => ({
            ...styles.navLink,
            backgroundColor: isActive ? "#2d8a5e" : "transparent",
            borderBottom: isActive ? "3px solid #fff" : "3px solid transparent",
          })}
        >
          🏠 Trang Chủ
        </NavLink>
        <NavLink
          to="/products"
          style={({ isActive }) => ({
            ...styles.navLink,
            backgroundColor: isActive ? "#2d8a5e" : "transparent",
            borderBottom: isActive ? "3px solid #fff" : "3px solid transparent",
          })}
        >
          🏪 Tất Cả Sản Phẩm
        </NavLink>
        {categories.map((cat) => (
          <NavLink
            key={cat.key}
            to={`/category/${cat.key}`}
            style={({ isActive }) => ({
              ...styles.navLink,
              backgroundColor: isActive ? "#2d8a5e" : "transparent",
              borderBottom: isActive ? "3px solid #fff" : "3px solid transparent",
            })}
          >
            {cat.icon} {cat.label}
          </NavLink>
        ))}
      </nav>
    </header>
  );
}

const styles = {
  header: {
    backgroundColor: "#38a169",
    boxShadow: "0 2px 8px rgba(0,0,0,0.2)",
    position: "sticky",
    top: 0,
    zIndex: 1000,
  },
  topBar: {
    display: "flex",
    alignItems: "center",
    justifyContent: "space-between",
    padding: "12px 32px",
    gap: "16px",
    maxWidth: "1400px",
    margin: "0 auto",
  },
  logo: {
    display: "flex",
    alignItems: "center",
    gap: "8px",
    cursor: "pointer",
    flexShrink: 0,
  },
  logoIcon: { fontSize: "28px" },
  logoText: {
    color: "white",
    fontSize: "22px",
    fontWeight: "800",
    letterSpacing: "1px",
    fontFamily: "sans-serif",
  },
  logoSub: {
    color: "#c6f6d5",
    fontSize: "11px",
    fontFamily: "sans-serif",
    alignSelf: "flex-end",
    marginBottom: "2px",
  },
  searchBar: {
    display: "flex",
    flex: 1,
    maxWidth: "500px",
    borderRadius: "8px",
    overflow: "hidden",
    boxShadow: "0 1px 4px rgba(0,0,0,0.15)",
  },
  searchInput: {
    flex: 1,
    padding: "10px 16px",
    border: "none",
    fontSize: "14px",
    outline: "none",
    fontFamily: "sans-serif",
  },
  searchBtn: {
    backgroundColor: "#f6ad55",
    border: "none",
    padding: "10px 16px",
    cursor: "pointer",
    fontSize: "16px",
  },
  topRight: {
    display: "flex",
    alignItems: "center",
    gap: "16px",
    flexShrink: 0,
  },
  cartBtn: {
    display: "flex",
    alignItems: "center",
    gap: "10px",
    cursor: "pointer",
    backgroundColor: "rgba(255,255,255,0.15)",
    padding: "8px 16px",
    borderRadius: "8px",
    position: "relative",
    transition: "background 0.2s",
  },
  cartIcon: { fontSize: "24px" },
  cartInfo: {
    display: "flex",
    flexDirection: "column",
  },
  cartLabel: {
    color: "#c6f6d5",
    fontSize: "11px",
    fontFamily: "sans-serif",
  },
  cartCount: {
    color: "white",
    fontSize: "13px",
    fontWeight: "600",
    fontFamily: "sans-serif",
  },
  cartBadge: {
    position: "absolute",
    top: "-6px",
    right: "-6px",
    backgroundColor: "#fc8181",
    color: "white",
    borderRadius: "50%",
    width: "20px",
    height: "20px",
    fontSize: "11px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontWeight: "700",
    fontFamily: "sans-serif",
  },
  navBar: {
    display: "flex",
    backgroundColor: "#2f855a",
    overflowX: "auto",
    padding: "0 32px",
  },
  navLink: {
    color: "white",
    textDecoration: "none",
    padding: "10px 14px",
    fontSize: "13px",
    fontWeight: "500",
    whiteSpace: "nowrap",
    fontFamily: "sans-serif",
    transition: "background 0.2s",
  },
};

export default Menu;
